use std::cell::OnceCell;
use std::io::{self, Read};
use std::fs::File;

struct AppConfig {
    data: String
}

impl AppConfig {
    fn load_from_file(path: &str) -> io::Result<Self> {
        let mut file = File::open(path)?;
        let mut buffer = String::new();
        file.read_to_string(&mut buffer)?;
        Ok(AppConfig { data: buffer })
    }
}

struct ConfigManager {
    config: OnceCell<AppConfig>,
}

impl ConfigManager {
    fn new() -> Self {
        ConfigManager { config: OnceCell::new() }
    }

    fn initialize(&self, path: &str) -> io::Result<()> {
        let initial_config = AppConfig::load_from_file(path)?;
        self.config.set(initial_config).expect("Configuration already set!");
        Ok(()) 
    }

    fn get_current_state(&self) -> io::Result<&AppConfig> {
        match self.config.get() {
            Some(config) => Ok(config),
            None => Err(io::Error::new(io::ErrorKind::NotFound, "Config not initialized"))
        }
    }

    fn refresh_state(&self, path: &str) -> io::Result<()> {
        let new_config = AppConfig::load_from_file(path)?;
        self.config.set(new_config).expect("Failed to update config!");
        Ok(())
    }
}

fn main() -> io::Result<()> {
    use std::fs;

    let temp_file = "temp_settings.txt";
    fs::write(temp_file, "Initial API Key 123")?;

    let manager = ConfigManager::new();
    manager.initialize(temp_file)?;

    println!("Startup State: {}", manager.get_current_state()?.data);

    fs::write(temp_file, "Updated Secret Key 456")?;
    manager.refresh_state(temp_file)?;

    println!("Refreshed State: {}", manager.get_current_state()?.data);

    fs::remove_file(temp_file)?; 
    Ok(())
}
